insert into reviews (dish_id, who, img, text, sort) values
  ('d01', 'Mia', 12, 'Leopard-spotted crust, molten center. Worth the line down 8th.', 0),
  ('d01', 'Devon', 53, 'Basil goes on after the oven — you can taste it.', 1),
  ('d02', 'Iris', 47, 'Broth simmered 18 hours. The egg is jammy perfection.', 0),
  ('d02', 'Theo', 14, 'Get the extra nori. Trust me.', 1),
  ('d03', 'Suki', 32, 'The tahini drizzle does heavy lifting. Great before a Nats game.', 0),
  ('d04', 'Marco', 68, 'Crust on the patty like a steakhouse sear.', 0),
  ('d04', 'Lena', 44, 'Sauce drips down your wrist. A good sign.', 1),
  ('d05', 'Aki', 25, 'Lighter than it looks. Eat it on the canal steps.', 0),
  ('d06', 'Noor', 31, 'Bread for the sauce is non-negotiable. Sit outside if you can.', 0),
  ('d07', 'Caleb', 59, 'Maple gets warmed. Beats the Eastern Market brunch lines.', 0),
  ('d08', 'Jun', 11, 'Rice at body temperature — they care here.', 0),
  ('d08', 'Priya', 41, 'The scallop one ruined other sushi for me.', 1),
  ('d09', 'Rosa', 26, 'Pink edge to edge. Perfect before a 9:30 Club show.', 0),
  ('d10', 'Sam', 15, 'Five ingredients. Zero notes.', 0),
  ('d11', 'Farah', 38, 'They crack the pastry seal at the table. Theater.', 0),
  ('d12', 'Elle', 21, 'Simple, but the bread is the point. Staffer crowd by 9am.', 0),
  ('d13', 'Kai', 64, 'Pretty AND structurally sound.', 0),
  ('d14', 'Vera', 49, 'Came for a date, stayed for the beurre blanc.', 0),
  ('d15', 'Owen', 18, 'Skin crisps like a chip. Eat it first.', 0),
  ('d16', 'Gus', 56, 'Sweet heat. Classier than a 2am jumbo slice, same joy.', 0),
  ('d17', 'Tess', 35, 'Custardy middle, torched top. Dessert for breakfast.', 0),
  ('d18', 'Dre', 60, 'Open till 2 on weekends. Fries stay crispy to the bottom of the bag.', 0),
  ('d19', 'Yuki', 29, 'Actually filling, which is rare for this genre.', 0),
  ('d20', 'Anya', 43, 'Smoke from the tandoor comes through.', 0),
  ('d21', 'Wen', 22, 'Numbing, tingly, perfect. Order the cucumbers too.', 0),
  ('d22', 'Remy', 51, 'Cooked rosy. Sauce belongs in a Smithsonian.', 0),
  ('d23', 'Bo', 13, 'Eggs from a Shenandoah farm they name on the menu.', 0),
  ('d24', 'Hana', 36, 'Break the yolk, toss fast, thank me later.', 0),
  ('d25', 'Nico', 66, 'Little grease cups of joy.', 0),
  ('d26', 'Isla', 40, 'Vegetables treated like the main event.', 0);
